  "inlineSchema": "// Global schema — all models live in the public PostgreSQL schema.\n// All shops share the same tables, isolated by tenant_id foreign key.\n//\n// Commands:\n//   prisma migrate dev   → apply migrations\n//   prisma generate      → regenerate the Prisma client\n\ngenerator client {\n  provider      = \"prisma-client-js\"\n  binaryTargets = [\"native\", \"rhel-openssl-3.0.x\"]\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─── Enums ────────────────────────────────────────────────────────────────────\n\nenum TenantStatus {\n  ACTIVE\n  INACTIVE\n  SUSPENDED\n  PENDING\n}\n\nenum AppointmentStatus {\n  PENDING\n  CONFIRMED\n  COMPLETED\n  CANCELLED\n}\n\n// ─── Tenant (Shop) ────────────────────────────────────────────────────────────\n\nmodel Tenant {\n  id          String       @id @default(uuid())\n  shopName    String       @map(\"shop_name\")\n  subdomain   String       @unique\n  schemaName  String       @unique @map(\"schema_name\")\n  ownerEmail  String       @map(\"owner_email\")\n  ownerName   String?      @map(\"owner_name\")\n  password    String?\n  description String?\n  email       String?\n  bannerUrl   String?      @map(\"banner_url\")\n  phone       String?\n  address     String?\n  image       String?\n  rating      Float        @default(5.0)\n  status      TenantStatus @default(ACTIVE)\n  createdAt   DateTime     @default(now()) @map(\"created_at\")\n  updatedAt   DateTime     @updatedAt @map(\"updated_at\")\n\n  hours        ShopHours[]\n  location     ShopLocation?\n  treatments   Treatment[]\n  artisans     Artisan[]\n  reviews      Review[]\n  appointments Appointment[]\n\n  @@map(\"tenants\")\n}\n\n// ─── Super Admin ──────────────────────────────────────────────────────────────\n\nmodel SuperAdmin {\n  id        String   @id @default(uuid())\n  email     String   @unique\n  password  String\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"super_admins\")\n}\n\n// ─── Customer (end-user who books appointments) ───────────────────────────────\n\nmodel Customer {\n  id        String   @id @default(uuid())\n  userId    String   @unique @map(\"user_id\")\n  fullName  String   @map(\"full_name\")\n  email     String   @unique\n  phone     String\n  password  String\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  appointments Appointment[]\n\n  @@map(\"customers\")\n}\n\n// ─── Auth ─────────────────────────────────────────────────────────────────────\n\nmodel RefreshToken {\n  id        String   @id @default(uuid())\n  tokenHash String   @unique @map(\"token_hash\")\n  role      String\n  entityId  String   @map(\"entity_id\")\n  expiresAt DateTime @map(\"expires_at\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"refresh_tokens\")\n}\n\n// ─── Shop Management ──────────────────────────────────────────────────────────\n\nmodel ShopHours {\n  id        String  @id @default(uuid())\n  tenantId  String  @map(\"tenant_id\")\n  day       String\n  isOpen    Boolean @map(\"is_open\")\n  openTime  String  @map(\"open_time\")\n  closeTime String  @map(\"close_time\")\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@unique([tenantId, day])\n  @@map(\"shop_hours\")\n}\n\nmodel ShopLocation {\n  id          String  @id @default(uuid())\n  tenantId    String  @unique @map(\"tenant_id\")\n  street      String?\n  city        String?\n  state       String?\n  zip         String?\n  country     String?\n  latitude    Float?\n  longitude   Float?\n  mapEmbedUrl String? @map(\"map_embed_url\")\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@map(\"shop_locations\")\n}\n\nmodel Treatment {\n  id          String   @id @default(uuid())\n  tenantId    String   @map(\"tenant_id\")\n  name        String\n  description String?\n  price       Float\n  duration    Int\n  status      String   @default(\"Active\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  tenant       Tenant        @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  appointments Appointment[]\n\n  @@map(\"treatments\")\n}\n\nmodel Artisan {\n  id        String   @id @default(uuid())\n  tenantId  String   @map(\"tenant_id\")\n  name      String\n  specialty String?\n  bio       String?\n  avatarUrl String?  @map(\"avatar_url\")\n  isActive  Boolean  @default(true) @map(\"is_active\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  tenant       Tenant        @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  appointments Appointment[]\n\n  @@map(\"artisans\")\n}\n\nmodel Review {\n  id           String   @id @default(uuid())\n  tenantId     String   @map(\"tenant_id\")\n  customerName String   @map(\"customer_name\")\n  rating       Int\n  comment      String?\n  isFeatured   Boolean  @default(false) @map(\"is_featured\")\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@map(\"reviews\")\n}\n\n// ─── Appointments (universal — all shops share this table) ───────────────────\n\nmodel Appointment {\n  id              String            @id @default(uuid())\n  tenantId        String            @map(\"tenant_id\")\n  customerId      String            @map(\"customer_id\")\n  treatmentId     String            @map(\"treatment_id\")\n  artisanId       String?           @map(\"artisan_id\")\n  appointmentDate DateTime          @map(\"appointment_date\")\n  appointmentTime String            @map(\"appointment_time\")\n  status          AppointmentStatus @default(PENDING)\n  notes           String?\n  createdAt       DateTime          @default(now()) @map(\"created_at\")\n  updatedAt       DateTime          @updatedAt @map(\"updated_at\")\n\n  tenant    Tenant    @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  customer  Customer  @relation(fields: [customerId], references: [id], onDelete: Cascade)\n  treatment Treatment @relation(fields: [treatmentId], references: [id], onDelete: Cascade)\n  artisan   Artisan?  @relation(fields: [artisanId], references: [id])\n\n  @@map(\"appointments\")\n}\n",
